// ─── Region coordinates ─────────────────────────────────────────────

export interface RegionInfo {
  /** SVG x coordinate (longitude) */
  x: number
  /** SVG y coordinate (negated latitude for SVG space) */
  y: number
  /** Human-readable display name */
  display: string
}

export const REGION_COORDS: Record<string, RegionInfo> = {
  pdx: { x: -122.68, y: -45.52, display: 'Portland, OR' },
  lax: { x: -118.24, y: -34.05, display: 'Los Angeles, CA' },
  nyc: { x: -74.01, y: -40.71, display: 'New York, NY' },
  fra: { x: 8.68, y: -50.11, display: 'Frankfurt, DE' },
  tyo: { x: 139.69, y: -35.69, display: 'Tokyo, JP' },
  syd: { x: 151.21, y: 33.87, display: 'Sydney, AU' },
  lon: { x: -0.12, y: -51.51, display: 'London, UK' },
  dal: { x: -96.80, y: -32.78, display: 'Dallas, TX' },
  sjc: { x: -121.89, y: -37.34, display: 'San Jose, CA' },
  _default: { x: -98.58, y: -39.83, display: 'Central US' },
}

/** Resolve a region code to its coordinate info, falling back to _default. */
export function regionInfo(code: string): RegionInfo {
  return REGION_COORDS[code] ?? REGION_COORDS._default
}

